const input = $input.first().json;
const prompt = `Write a cover letter. NEVER hallucinate facts.\n\nJob Title: ${input.job.title}\nCompany Name: ${input.job.company_name}\nDescription: ${input.job.description || ''}\n\nCandidate Resume Data:\n${JSON.stringify(input.tailored_resume)}`;

return [{
  json: {
    job_id: input.job.job_id || input.job.dedup_hash,
    prompt,
    model: $env.MODEL_COVER_LETTER || 'anthropic/claude-haiku-3'
  }
}];

